#include <bits/stdc++.h>
using namespace std;
const int maxn=5e5+5;
unordered_map<int,int> cnts;
int n,cnt,ans=INT_MAX;
int z(int id) {
	if(++cnts[id]==1) {
		cnt++;
	}
	return 0;
}
int jj(int id) {
	if(--cnts[id]==0) {
		cnt--;
	}
	return 0;
}
struct cow {
	int x,id;
} a[maxn];

bool cmp(cow a,cow b) {
	return a.x<b.x;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	cnts.clear();
	unordered_set<int> b;
	for(int i=1; i<=n; i++) {
		cin>>a[i].x>>a[i].id;
		b.insert(a[i].id);
	}
	sort(a+1,a+1+n,cmp);
	int l=b.size();
	for(int i=1,j=1; i<=n; i++) {
		z(a[i].id);
		while(cnt==l&&j<=i) {
			ans=min(ans,a[i].x-a[j].x);
			jj(a[j].id);
			j++;
		}
	}
	cout<<ans;
	return 0;
}
